import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirUserActions } from '../HIRUsers';
import { hirUtil, MyDialog, MyTable, simplePaginationConfig, errorNotice, HighlightedInfo, headerActions, headerStrings, breadCrumbActions, SimplePagination, appActions } from '../utils';
import { Button, IconButton, List, ListItem, ListItemText, Popover, Table, TableBody, TableCell, TableHead, TableRow } from '@material-ui/core';
import { MoreVert } from '@material-ui/icons';
import { hirAccountActions } from '../HIRAccounts';
import { HIRNewDeposit } from '../HIRDeposits/HIRNewDeposit';
import { hirRouteNames } from '../routeNames';
import exportFromJSON from 'export-from-json'


const style = theme => ({
    root: {
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    iconBtn : {
        padding : 2.5,
    },
    download : {
        fontSize : 12,
        textDecoration : "underline",
        "&:hover" : {
            cursor : "pointer",
        }
    }
})
class _HIRDebtors extends Component {
    constructor(props) {
        super(props);
        this.state = {
            openDialog : false,
            dialogType : null,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "Debtors",
            [headerStrings.backButtonAction] : null,
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : hirRouteNames.dashboard},
            {name : "Debtors", path : hirRouteNames.debtors},
        ])(dispatch);
    }
    
    componentDidMount() {
        this.debtorConfig();
    }
    
    debtorConfig(){
        this.pageControl = simplePaginationConfig(
            this, this.getDebtors, this.props.dispatch,
            "debtors", 50, null, null, this.getDebtorMinMaxIds,
            this.searchDebtors, this.getSearchDebtorMinMaxIds
        )
        this.pageControl.getAction();
    }
    getFilter(){
        return {"debt" : {$exists : true}};
    }
    getDebtors = (rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirUserActions.getDebtors(filter, rows, skip, sort, max, callback)(dispatch);
    }
    getDebtorMinMaxIds = (sort, callback)=> dispatch => {
        const filter = this.getFilter();
        hirUserActions.getDebtorMinMaxIds(filter, sort, callback)(dispatch);
    }
    searchDebtors = (keyword, rows, skip, sort, max, callback)=>dispatch => {
        const filter = this.getFilter();
        hirUserActions.searchDebtors(filter, keyword, rows, skip, sort, max, callback)(dispatch);
    }
    getSearchDebtorMinMaxIds = (keyword, sort, callback)=>dispatch => {
        const filter = this.getFilter();
        hirUserActions.getSearchDebtorMinMaxIds(filter, keyword, sort, callback)(dispatch);
    }
    onMoreClick = row => (e)=> {
        e.stopPropagation();
        const anchorEl = e.target;
        this.setState({anchorEl, debtor : row});
    }
    balanceOutDebt = debtor => {
        const {dispatch} = this.props,
        patientId = debtor._id;
        hirAccountActions.balanceOutDebt(patientId, done => {
            this.setState({anchorEl : null});
            done && this.pageControl.getAction()
        })(dispatch);
    }
    closeDialog = () => this.setState({openDialog : false, dialotType : null});
    createDeposit(data, callback){
        const {debtor} = this.state,
        {dispatch} = this.props;
        if(!debtor) return errorNotice("No debtor selected", dispatch);
        const {_id : patientId, debt} = debtor,
        {amount} = data;
        if(debt > amount) return errorNotice("The amount stated can't cover the debt! Please increase the amount to match the debt!", dispatch);
        hirAccountActions.createDeposit({...data, patientId}, done => {
            callback && callback();
            if(done){
                this.setState({dialogType : null, openDialog : null})
                this.balanceOutDebt(debtor);
            }
        })(dispatch);
    }
    header = ["ID", "Old ID", "Name", "Gender", "Age", "Phone", "Credit", "Debt", ""];
    headerMapper = ["_id", "oldId", "name", "gender", "age", "phone", "credit", "debt", "action"];
    downloadCVS(data){
        const {dispatch} = this.props,
        fileName = 'debtors',
        exportType = 'csv',
        mainData = []
        if(data) for (let i = 0; i < data.length; i++) {
            const dataObject = data[i],
            mainD = {},
            {myProfile} = dataObject || {};
            for (let j = 0; j < this.headerMapper.length; j++) {
                const mapper = this.headerMapper[j];
                let value = dataObject[mapper],
                header = this.header[j];
                switch(mapper){
                    case "actionDate" : 
                        mainD[header] = value && new Date(value).toLocaleDateString(); 
                        break;
                    case "credit" : 
                    case "debt" : 
                        mainD[header] = value && new Number(value).toLocaleString(); 
                        break;
                    case "age" : 
                        const age = myProfile && new Date().getFullYear() - new Date(myProfile.dob).getFullYear();
                        mainD[header] = age === 0 ? "< 1" : String(age); 
                        break;
                    case "oldId" : 
                    case "phone" : 
                        mainD[header] = myProfile && myProfile[mapper];
                        break;
                    case "gender" : 
                        mainD[header] = myProfile && myProfile[mapper] && (myProfile[mapper] === "m" ? "Male" : "Female");
                        break;
                    case "_id" : 
                        mainD[header] = dataObject?._id;
                        break;
                    case "actionDate" : 
                        mainD[header] = new Date(value).toLocaleDateString();
                        break;
                    case "name" : 
                        const {lastName, firstName} = myProfile || {},
                        name = (lastName ? lastName : "") + " " + (firstName ? firstName : "");
                        mainD[header] = name;
                        break;
                    default: mainD[header] = dataObject[mapper]; break;
                }
            }
            mainData.push(mainD);
        }
        appActions.showSnackDialog(
            "You are about to download a CSV file. Do you want to continue?",
            [<Button key="downloadCSV" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                exportFromJSON({ data : mainData, fileName, exportType })
            }}>Continue</Button>]
        )(dispatch);
    }
    render() {
        const {classes, dispatch} = this.props,
        {debtors=[], anchorEl, openDialog, dialogType, debtor} = this.state;
        const headers = this.header;
        const headerMapper = this.headerMapper;
        return (
            <div className={classes.root}>          
                <HighlightedInfo>
                    You can only <strong>settle debt</strong> with amount equivalent to the debt,
                    else you would go through <strong>deposits</strong> and make the deposit, then come back to balance it out.
                </HighlightedInfo>
                <Table stickyHeader size="medium">
                    <TableHead>
                        <TableRow>
                            {headers.map((head, index)=>{
                                return <TableCell key={index} className={classes.cell}>
                                    {head}
                                </TableCell>
                            })}
                        </TableRow>
                    </TableHead>    
                    <TableBody>
                        {debtors && debtors.map((debtor, index)=>{
                            return <TableRow key={index}>
                                {headerMapper.map((map, mapIndex)=>{
                                    const {myProfile} = debtor
                                    switch(map) {
                                        case "action" : return <TableCell key={index+mapIndex} className={classes.cell}>
                                            {hirUtil.isAdmin() && <IconButton className={classes.iconBtn} onClick={e=>{
                                                e.stopPropagation();
                                                const anchorEl = e.target;
                                                this.setState({anchorEl, debtor});
                                            }}>
                                                <MoreVert fontSize="small"/>
                                            </IconButton>}
                                        </TableCell>
                                        case "credit" : 
                                        case "debt" : return <TableCell key={index+mapIndex} className={classes.cell}>
                                            {debtor[map] ? Number(debtor[map]).toLocaleString() : 0}
                                        </TableCell>
                                        case "gender" : return <TableCell key={index+mapIndex} className={classes.cell}>
                                            {myProfile && myProfile[map] && (myProfile[map] === "m" ? "Male" : "Female")}
                                        </TableCell>
                                        case "age" : 
                                            const age = myProfile && new Date().getFullYear() - new Date(myProfile.dob).getFullYear()
                                            return <TableCell key={index+mapIndex} className={classes.cell}>
                                                {age === 0 ? "< 1" : String(age)}
                                        </TableCell>
                                        case "name" : 
                                            let lastName, firstName, middleName;
                                            if(myProfile){
                                                lastName = myProfile.lastName;
                                                firstName = myProfile.firstName;
                                                middleName = myProfile.middleName;
                                            }
                                            return <TableCell key={index+mapIndex} className={classes.cell}>
                                            <strong>{String(lastName).trim()}</strong>, {
                                            (firstName ? firstName : "") + " " +(middleName ? middleName : "")}
                                        </TableCell>
                                        case "phone" : return <TableCell key={index+mapIndex} className={classes.cell}>
                                            {myProfile && myProfile.phone}
                                        </TableCell>
                                        case "_id" : return <TableCell key={index+mapIndex} className={classes.cell}>
                                            {String(debtor[map]).padStart(6, "0")}
                                        </TableCell>
                                        default : return <TableCell key={index+mapIndex} className={classes.cell}>
                                            {myProfile && myProfile[map]}
                                        </TableCell>
                                    }
                                })}
                            </TableRow>
                        })}
                    </TableBody>
                </Table>    
                
                {this.pageControl && debtors.length > 0 && <div style={{marginTop : 20}}>
                    <SimplePagination
                        nextBtnClick={this.pageControl.nextBtnOnClick()}
                        nextBtnProps={{
                            disabled : this.pageControl.nextBtnDisabled()
                        }}
                        prevBtnClick={this.pageControl.prevBtnOnClick()}
                        prevBtnProps={{
                            disabled : this.pageControl.prevBtnDisabled()
                        }}
                    />
                </div>}
                <div style={{display : "flex", justifyContent : "flex-end"}}>
                    <a onClick={()=>this.downloadCVS(debtors)} className={classes.download}>
                        Download CSV file
                    </a>
                </div>
                <MyDialog within
                    open={openDialog}
                    close={this.closeDialog.bind(this)}
                >
                    <HIRNewDeposit
                        onCancel={this.closeDialog.bind(this)}
                        onCreateDeposit={this.createDeposit.bind(this)}
                    />
                </MyDialog>
                <Popover
                    open={Boolean(anchorEl)}
                    anchorEl={anchorEl}
                    onClose={()=>this.setState({anchorEl : null})}>
                    <List>
                        <ListItem button onClick={() => this.balanceOutDebt(debtor)}>
                            <ListItemText secondary="Balance out"/>
                        </ListItem>
                        <ListItem button onClick={()=>{
                            const {credit, debt} = debtor;
                            if(credit) return errorNotice("Balance out first with the available credit!", dispatch);
                            this.setState({openDialog : true, dialogType : "deposit", anchorEl : null})
                        }}>
                            <ListItemText secondary="Settle Debt"/>
                        </ListItem>
                    </List>
                </Popover>
            </div>
        );
    }
}


_HIRDebtors.propTypes = {
    classes : PropTypes.object.isRequired
};
export const HIRDebtors = connect()(withStyles(style)(_HIRDebtors));
export {HIRDebtors as default}